// GetOnlyEUR2 – VERSÃO 100% SUPABASE-PROOF (2025)
// Garante ISO 8601 com Z → nunca mais erro de timestamp

const rates = $json.rates;
const EURPrice = rates?.EUR;

if (EURPrice === undefined) {
  throw new Error("EUR rate not found in API response");
}

// time_last_update_utc já vem como string ISO do open.er-api (ex: "2025-11-28 09:58:01")
const apiTimeRaw = $json.time_last_update_utc?.trim();

// Usa o timestamp da API se existir e for válido, senão usa agora
let market_data_at;
if (apiTimeRaw && apiTimeRaw.match(/^\d{4}-\d{2}-\d{2}/)) {
  // Força Z no final (a API às vezes manda sem Z)
  market_data_at = apiTimeRaw.endsWith('Z') ? apiTimeRaw : apiTimeRaw + 'Z';
} else {
  market_data_at = new Date().toISOString();
}

// Timestamp de processamento (exato momento que o n8n rodou)
const processed_at_utc = new Date().toISOString();

return [
  {
    json: {
      coin: "EUR",
      price: parseFloat(EURPrice.toFixed(6)),  // mantemos 6 casas (padrão câmbio)
      market_data_at: market_data_at,         // ← horário oficial da cotação (com Z)
      processed_at_utc: processed_at_utc      // ← horário que entrou no seu sistema (com Z)
    }
  }
];

const executionId = $execution.id;
let sqlStatements = [];

// Constante: quantidade de gramas em uma onça troy
const GRAMS_PER_TROY_OUNCE = 31.1034768;

// Função para calcular o preço da onça troy a partir do preço por grama
function calculateTroyOuncePrice(pricePerGram) {
  // Multiplica pelo número de gramas em uma onça troy
  return pricePerGram * GRAMS_PER_TROY_OUNCE;
}

for (const entry of $input.all()) {

  const records = entry.json.valorioro?.valoreoro || [];
  const usdRate = parseFloat(entry.json.price); // ainda mantém usdRate para registro na coluna existente

  if (!usdRate) {
    throw new Error("USD rate not received from API");
  }

  for (const item of records) {

    if (item.materiale !== 'oro') continue;        // filtra apenas ouro
    if (parseInt(item.carati) !== 24) continue;    // filtra apenas ouro 24K
    if (!item.valore || item.valore === "0") continue;  // ignora valores inválidos

    const [datePart, timePart] = item.lastdate.split(" ");
    const [day, month, year] = datePart.split("/");

    const rateDate = `${year}-${month}-${day} ${timePart}`;

    const material = 'oro';
    const carati = 24;
    const valor = parseFloat(item.valore);
    const rawJson = JSON.stringify(item).replace(/'/g, "''");

    // Calcula o preço da onça troy em moeda local (sem conversão para USD)
    const ozPrice = calculateTroyOuncePrice(valor);

    // INSERÇÃO NO HISTÓRICO
    sqlStatements.push(`
      IF NOT EXISTS (
        SELECT 1
        FROM Metal_Rates_History
        WHERE RateDate='${rateDate}'
        AND Material='oro'
        AND Carati=24
      )
      INSERT INTO Metal_Rates_History
      (ExecutionId, Material, Carati, Valor, RateDate, RawJson, Price_USD_EU, Oz_Price)
      VALUES
      ('${executionId}', '${material}', ${carati}, ${valor}, '${rateDate}', '${rawJson}', ${usdRate}, ${ozPrice});
    `);

    // ATUALIZAÇÃO OU INSERÇÃO NO REGISTRO ATUAL
    sqlStatements.push(`
      IF EXISTS (
        SELECT 1 FROM Metal_Rates_Current
        WHERE Material='${material}' AND Carati=${carati}
      )
        UPDATE Metal_Rates_Current
        SET
          Valor=${valor},
          RateDate='${rateDate}',
          ExecutionId='${executionId}',
          Price_USD_EU=${usdRate},
          Oz_Price=${ozPrice},
          UpdatedAt=GETDATE()
        WHERE Material='${material}' AND Carati=${carati};
      ELSE
        INSERT INTO Metal_Rates_Current
        (ExecutionId, Material, Carati, Valor, RateDate, Price_USD_EU, Oz_Price, UpdatedAt)
        VALUES
        ('${executionId}', '${material}', ${carati}, ${valor}, '${rateDate}', ${usdRate}, ${ozPrice}, GETDATE());
    `);

  }
}

if (sqlStatements.length === 0) {
  throw new Error('24K gold rate not found in API response');
}

const finalQuery = `
BEGIN TRY
  BEGIN TRANSACTION;

  ${sqlStatements.join('\n')}

  COMMIT TRANSACTION;
END TRY
BEGIN CATCH
  IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
  THROW;
END CATCH;
`;

return [
  {
    json: {
      query: finalQuery
    }
  }
];

const executionId = $execution.id;

const query = `
DECLARE @TargetDate DATE = CAST(DATEADD(day,-1,GETDATE()) AS DATE);

IF NOT EXISTS (
    SELECT 1
    FROM Metal_Rates_Daily
    WHERE RateDate = @TargetDate
    AND Material = 'oro'
    AND Carati = 24
)
BEGIN

    INSERT INTO Metal_Rates_Daily
    (
        RateDate,
        Material,
        Carati,
        Valor,
        RawJson,
        ExecutionId,
        Price_USD_EU,
        Oz_Price,
        CreatedAt
    )

    SELECT TOP 1
        CAST(RateDate AS DATE),
        Material,
        Carati,
        Valor,
        RawJson,
        '${executionId}',
        Price_USD_EU,
        Oz_Price,
        GETDATE()

    FROM Metal_Rates_History

    WHERE
        Material = 'oro'
        AND Carati = 24
        AND CAST(RateDate AS DATE) = @TargetDate

    ORDER BY RateDate DESC;

END
`;

const finalQuery = `
BEGIN TRY

    BEGIN TRANSACTION;

    ${query}

    COMMIT TRANSACTION;

END TRY
BEGIN CATCH

    IF @@TRANCOUNT > 0
        ROLLBACK TRANSACTION;

    THROW;

END CATCH;
`;

return [{
  json: {
    query: finalQuery
  }
}];
